import{_ as e,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"选主与分布式协调","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/14-ZooKeeper学习/04-选主与分布式协调.md","filePath":"语言/java/14-ZooKeeper学习/04-选主与分布式协调.md","lastUpdated":1776149370000}'),t={name:"语言/java/14-ZooKeeper学习/04-选主与分布式协调.md"};function _(o,a,h,n,d,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="选主与分布式协调" tabindex="-1">选主与分布式协调 <a class="header-anchor" href="#选主与分布式协调" aria-label="Permalink to “选主与分布式协调”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>ZooKeeper 常被用于选主、分布式锁、成员管理和任务协调。<br> 这些场景本质上都属于“多节点之间如何达成一致动作”的问题。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>分布式系统一复杂，就会遇到协调问题。<br> 理解 ZooKeeper 的协调能力，能帮助你更好地看懂很多中间件和注册中心的设计。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>选主基本思路</li><li>临时顺序节点</li><li>分布式锁基础认知</li><li>成员列表维护</li><li>协调流程设计</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解协调问题通常不是“共享变量”这么简单</li><li>理解临时顺序节点在协调中的高频价值</li><li>理解协调方案必须考虑异常退出和会话失效</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>只考虑正常路径不考虑异常节点</li><li>锁释放和会话关系不清楚</li><li>协调过程缺少超时与兜底设计</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>设计一个简化版选主流程</li><li>画一张基于临时顺序节点的锁流程图</li><li>总结协调方案里的风险点</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>为什么临时顺序节点适合做选主和锁</li><li>选主方案为什么一定要考虑故障恢复</li><li>分布式协调和单机同步有什么本质差异</li></ul>',15)])])}const b=e(t,[["render",_]]);export{p as __pageData,b as default};
